oxy_webhelp_navlinks = {"dashboards_overview-d526e164":{"topics":[{"title":"Installing sample dashboards","shortdesc":"<p class=\"shortdesc\">After you install and enable the <span class=\"ph\">IBM RMF for z\/OS Grafana<\/span>         plugin, you can install the DDS sample dashboards and Prometheus sample dashboards to         visualize RMF metrics.<\/p>","href":"install_sample_dashboards.html","attributes":{"data-id":"install_sample_dashboards"},"menu":{"hasChildren":false},"tocID":"install_sample_dashboards-d526e178","topics":[]},{"title":"Prometheus sample dashboards","shortdesc":"<p class=\"shortdesc\">The RMF <span class=\"ph\">Distributed Data Server<\/span> exposes Monitor III data to         third-party tools using the OpenMetrics exposition format.<\/p>","href":"prometheus_sample_db.html","attributes":{"data-id":"prometheus_sample_db"},"menu":{"hasChildren":false},"tocID":"prometheus_sample_db-d526e192","topics":[]},{"title":"Integrating DDS dashboards with OMEGAMON Web UI","shortdesc":"<p class=\"shortdesc\">To enhance visibility and provide deeper insights, the DDS dashboards can be         integrated with IBM Z OMEGAMON Web UI dashboards. <\/p>","href":"integrating_dds_omegamon.html","attributes":{"data-id":"integrating_dds_omegamo"},"menu":{"hasChildren":false},"tocID":"integrating_dds_omegamo-d526e206","topics":[]},{"title":"Importing Performance Monitoring dashboards","shortdesc":"<p class=\"shortdesc\">You can import dashboards exported from RMF Performance Monitoring             (<span class=\"ph filepath\">.po<\/span> files) into the <span class=\"ph\">IBM RMF for z\/OS Grafana<\/span> plugin. The import process automatically         creates the associated data sources and converts the dashboards to Grafana format.<\/p>","href":"importing_dashboards.html","attributes":{"data-id":"importing_dashboards"},"menu":{"hasChildren":false},"tocID":"importing_dashboards-d526e217","topics":[]}]}};